  "name": "@kntic/links",
  "version": "0.1.0",
  "description": "CLI for building and deploying self-hosted link-in-bio pages. No accounts, no tracking — just HTML.",
  "type": "module",
  "license": "MIT",
  "bin": {
    "links": "src/cli.js"
  },
  "files": [
    "src/",
    "LICENSE",
    "README.md"
  ],
